"""sklearn.gaussian_process — Gaussian Process regression and classification."""
import numpy as np
from sklearn.base import BaseEstimator, RegressorMixin, ClassifierMixin


def _rbf_kernel(X1, X2, length_scale=1.0):
    """Compute the RBF (squared exponential) kernel."""
    X1 = np.asarray(X1, dtype=float)
    X2 = np.asarray(X2, dtype=float)
    sq_dist = np.sum(X1 ** 2, axis=1, keepdims=True) + \
              np.sum(X2 ** 2, axis=1) - 2 * X1 @ X2.T
    return np.exp(-0.5 * sq_dist / (length_scale ** 2))


class GaussianProcessRegressor(BaseEstimator, RegressorMixin):
    """Gaussian Process Regressor with RBF kernel.

    Parameters
    ----------
    length_scale : float, default=1.0
    alpha : float, default=1e-10
        Noise variance added to the diagonal.
    """

    def __init__(self, length_scale=1.0, alpha=1e-10, random_state=None):
        self.length_scale = length_scale
        self.alpha = alpha
        self.random_state = random_state

    def fit(self, X, y):
        self.X_train_ = np.asarray(X, dtype=float)
        self.y_train_ = np.asarray(y, dtype=float)
        K = _rbf_kernel(self.X_train_, self.X_train_, self.length_scale)
        K += self.alpha * np.eye(K.shape[0])
        self.L_ = np.linalg.cholesky(K)
        self.alpha_ = np.linalg.solve(self.L_.T, np.linalg.solve(self.L_, self.y_train_))
        return self

    def predict(self, X, return_std=False):
        X = np.asarray(X, dtype=float)
        K_star = _rbf_kernel(X, self.X_train_, self.length_scale)
        y_mean = K_star @ self.alpha_
        if return_std:
            v = np.linalg.solve(self.L_, K_star.T)
            K_ss = _rbf_kernel(X, X, self.length_scale)
            y_var = np.diag(K_ss) - np.sum(v ** 2, axis=0)
            y_std = np.sqrt(np.maximum(y_var, 0))
            return y_mean, y_std
        return y_mean


class GaussianProcessClassifier(BaseEstimator, ClassifierMixin):
    """Gaussian Process Classifier (Laplace approximation with RBF kernel).

    Simplified binary/multiclass classifier using GP regression on
    one-hot encoded labels.

    Parameters
    ----------
    length_scale : float, default=1.0
    alpha : float, default=1e-5
    """

    def __init__(self, length_scale=1.0, alpha=1e-5, random_state=None):
        self.length_scale = length_scale
        self.alpha = alpha
        self.random_state = random_state

    def fit(self, X, y):
        self.classes_ = np.unique(y)
        X = np.asarray(X, dtype=float)
        y = np.asarray(y)
        self.gps_ = []
        for c in self.classes_:
            gp = GaussianProcessRegressor(length_scale=self.length_scale, alpha=self.alpha)
            gp.fit(X, (y == c).astype(float))
            self.gps_.append(gp)
        return self

    def predict(self, X):
        proba = self.predict_proba(X)
        return self.classes_[np.argmax(proba, axis=1)]

    def predict_proba(self, X):
        X = np.asarray(X, dtype=float)
        raw = np.column_stack([gp.predict(X) for gp in self.gps_])
        # Softmax
        raw -= raw.max(axis=1, keepdims=True)
        exp_raw = np.exp(raw)
        return exp_raw / exp_raw.sum(axis=1, keepdims=True)
